import java.io.*;
import java.util.*;
public class Main{
    private static final int MAX_N=1000;
    public static void main(String[] args) throws Exception{
        boolean[] isPrime=new boolean[MAX_N+1];
        Arrays.fill(isPrime,true);
        isPrime[0]=isPrime[1]=false;
        for(int p=2;p*p<=MAX_N;++p) if(isPrime[p]) for(int m=p*p;m<=MAX_N;m+=p) isPrime[m]=false;
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st=new StringTokenizer(br.readLine());
        int L=Integer.parseInt(st.nextToken());
        int R=Integer.parseInt(st.nextToken());
        boolean first=true;
        for(int i=L;i<=R;++i) if(isPrime[i]){ if(!first) System.out.print(' '); System.out.print(i); first=false; }
        System.out.println();
    }
}

